sum(
  rate(
    {
      filesystem="${filesystem}",
      component="client_fs",
      __name__="Time",
      request=~"(ReadData|WriteData)",
      instance=~"$client",
    }
  )
) by(request)
  / on(request)
sum(
  rate(
    {
      filesystem="${filesystem}",
      component="client_fs",
      __name__=~"(Count|Errors)",
      request=~"(ReadData|WriteData)",
      instance=~"$client",
    }
  )
) by(request)

sum by(request)(
    increase(Errors{
      filesystem="${filesystem}",
      component="client_fs",
      request=~"ReadData|WriteData",
      instance=~"$client",
    }) keep_metric_names
)

sum by(__name__, request)(
    increase({
      filesystem="${filesystem}",
      component="client_fs",
      __name__=~"Errors_.*",
      request=~"ReadData|WriteData",
      instance=~"$client",
    }) keep_metric_names
)

WITH (
  commonFilters={
      filesystem="${filesystem}",
    component="client_fs",
    instance=~"$client",
  }
)
sum by (request)(rate(Time{commonFilters}))
/
sum by (request)(rate({commonFilters, __name__=~"(Count|Errors)"}))

max(
  label_replace(
    {
      filesystem="${filesystem}",
      component="client_fs",
      __name__="MaxTime",
      instance=~"$client",
    }, "request", "$1", "request", "(.*)"
  )
) by (request)

